		var CFG;
var TIT=null;
var arrA;

function setHidden()
{
	switch(Ctrl('main').GetMode())
	{
		case "ADD_ROL":
			Ctrl('d_param').SetXValue('Envío al rol: '+Ctrl('oi_role').GetCValue());
			Ctrl('d_param1').SetXValue(Ctrl('oi_role').GetXValue());
			Ctrl('d_param2').SetXValue("ROLE");
		break;
		case "ADD_MAIL":         
			Ctrl('d_param').SetXValue('Envío al mail: '+Ctrl('d_mail').GetXValue());
			Ctrl('d_param1').SetXValue(Ctrl('d_mail').GetXValue());
			Ctrl('d_param2').SetXValue("MAIL");
		break;
		case "ADD_ETTY":
			var entidad = Ctrl('oi_usuario_sistema').GetCValue().split(' - ');
			Ctrl('d_param').SetXValue('Envío a la entidad: '+entidad[1]);
			Ctrl('d_param1').SetXValue(Ctrl('oi_usuario_sistema').GetXValue());
			Ctrl('d_param2').SetXValue("ETTY");
		break;                                        
		case "ADD_FORMULA":
			Ctrl('d_param').SetXValue('Envío a la fórmula.');
			Ctrl('d_param1').SetXValue("Envío a la fórmula.");
			Ctrl('d_param2').SetXValue("FORMULA");
		break;				
	}
}

function add_dueno()
{ 
	var result = boton_add_dueno();

	if(result == "ok")
	{
		var MyControl = Ctrl("LIST");    
		refreshList("LIST", arrA);
		Ctrl('main').DoEvent("ADD_DUENO");
	}
	else
		alert("No puede agregar nuevamente al dueño como destinatario.");
}
