function del_destinatario()
{
	var MyID;

	if (Ctrl("list1arr") && Ctrl("list1arr").CountRow()>0)
	{ //Caso que hay esta checkeado elementos en la lista
		while(Ctrl("list1arr").CountRow()>0)
		{                                
			//Obtengo el ID del Elemento		
			MyID=Ctrl("list1arr").GetRow(0).GetAttr("id");

			//Elimino el Elemento
			if (Ctrl("list1arr"))
				Ctrl("list1arr").DelRow(0);
			delete arrA["k"+MyID];    
			Ctrl('resultado').DelRowByAttr('id', MyID);
		}
	} 

	refreshList("LIST", arrA);	
}

function del_all()
{ 
	var newArrA=new Array();

	for (key in arrA)
	{
		if (Ctrl("list1arr").GetRowByAttr("id",key.substr(1))!=null)
			newArrA[key]=arrA[key];
			Ctrl('resultado').DelRowByAttr('id', key.substr(1));
	}

	arrA = newArrA;
	if (Ctrl("list1arr")) Ctrl("list1arr").DelAllRow();
	refreshList("LIST", arrA);  	
	CtrlEnabled("btn_add_dueno", true);
}

function SAVE()
{
	if (Ctrl('main').GetMode()=="MAIL_ADD" || Ctrl('main').GetMode()=="MAIL_EDIT")
	{
		if (Ctrl("list1arr") && Ctrl("list1arr").CountRow()==0)
		{
			alert("Debe agregar al menos un destinatario");
			return;
		}
	}	

	if(Ctrl('main').GetMode()=="PARAM_ADD_SWITCH" || Ctrl('main').GetMode()=="PARAM_EDIT_SWITCH")
		if(Ctrl('c_type').GetXValue() == "CASE" && Ctrl('c_param').GetXValue() == "")
			alert("Debe cargar el valor para los parámetros de tipo CASE.");
		else
			Ctrl('main').DoEvent("SAVE");
	else
		Ctrl('main').DoEvent("SAVE");		

	if(Ctrl('main').GetMode()=="MAIN_ADD" || Ctrl('main').GetMode()=="MAIN_EDIT")
	{
		refreshList();
	} 	
}

function SetLabel()
{ 
	var label=Ctrl("d_label").GetXValue();

	if(Ctrl('main').GetMode() == "WAIT_TIME_ADD" || Ctrl('main').GetMode() == "WAIT_TIME_EDIT")
	{
		if(Ctrl('d_param_2').GetXValue() == "CANT_MIN")
		{
			var horas = Ctrl("d_param_1").GetXValue().substr(0,2);
			var minutos = Ctrl("d_param_1").GetXValue().substr(2,2);
			label = "Esperar " + horas + ":" + minutos;
		}
		else                         
		{
			var horas = Ctrl("d_param_1").GetXValue().substr(0,2);
			var minutos = Ctrl("d_param_1").GetXValue().substr(2,2);
			label = "Esperar a las " + horas + ":" + minutos;
		}
	}

	if(Ctrl('main').GetMode() == "STATUS_ADD" || Ctrl('main').GetMode() == "STATUS_EDIT")
		label = "Estado " + Ctrl("d_param_1").GetCValue();

	if(Ctrl('main').GetMode() == "FORM_ADD" || Ctrl('main').GetMode() == "FORM_EDIT")
		label = "Formulario " + Ctrl("d_param_1").GetCValue();

	if(Ctrl('main').GetMode() == "METHOD_ADD")           
		label = "Metodo externo " + Ctrl("d_param_1").GetCValue();

	Ctrl("d_label").SetXValue(label.toString());

}

function SetVar()
{ 
	var variable = Ctrl("GRID_PARAMS").GetCellSelectedXValue("c_param");                     
	Ctrl("GRID_PARAMS").SetCellXValue("c_var", Ctrl("GRID_PARAMS").SelectedRowIDX(), variable);
}

function SetOptionsCombo()
{
	var np, nSQL;
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();    

	OPTIONS = nSQL.Get(Ctrl("main").getResource("QRY_SUBPROCESOS"), 
	"<PARAM d_param_1=\""+Ctrl("d_param_1").GetXValue()+"\" />"); 

	Ctrl("d_param_2").setOptions(OPTIONS); 
}

function ReplaceResource(recID) {
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

function RefreshReport() {
	//Actualiza el reporte del formulario
	var strURL;

	strURL = "../../../ReportViewer.aspx?file=NucleusWF.Base.Definicion.WFPLA_Main.rpt" +
					"&ut=" + GetProxy().UserToken() +
					"&id=" + Ctrl("PARENT").GetXValue() +
					"&now=" + datetime2str(new Date());

	Ctrl("REPORT_ORG").SetURL(strURL);
}

