function OnLoad()
{                      
	arrA = new Array();
	var row;
	if (Ctrl("main").GetLastDoc("ARRA"))
	{             
		arrA = string2array(ELE2String(Ctrl("main").GetLastDoc("ARRA"))); 
		refreshList("LIST", arrA);
	}

	if (Ctrl('main').GetMode()=="MAIL_ADD" || Ctrl('main').GetMode()=="MAIL_EDIT")
	{
		remitente_onchange();	
	}

}              

function refreshList(strList, arr)
{                   
	Ctrl(strList).processResult(array2string(arr));
}

function string2array(str)
{
	var arr = new Array();
	var auxXml = new nomadDOM(str);

	for (i=0; i<auxXml.Child.length; i++)
	{
		arr["k" + auxXml.Child[i].id]=auxXml.Child[i];
	}
	return arr;
}

function array2string(arr)
{
	var retval = "";
	var key;
	for (key in arr)
	{
		retval+=ELE2String(arr[key].associatedELE);
	}

	return "<ROWS>"+retval+"</ROWS>";
}

function refrescarLista()
{
	Ctrl('resultado').DelAllRow();
 	for (key in arrA)
 	{          
 		var rowDestinatarios = Ctrl('resultado').AddRow();
 		rowDestinatarios.SetAttr('id', key.substr(1));
 	}                           
}

function boton_add_dueno()
{
	var ret = "ok";
	for (var i=0; i<Ctrl("resultado").CountRow(); i++) 
	{
		row = Ctrl("resultado").GetRow(i);		
		if (row.GetAttr("d_param2") == "OWNER")
		{
			ret = "mal";			
		}	
	}
	return ret;	
}

function EditFormula()
{
	var PARAM=new NomadXML("PARAM");

	PARAM.SetAttr("oi_workflow",Ctrl("oi_workflow"  ).GetXValue());
	PARAM.SetAttr("o_formula"  ,Ctrl("o_formula"    ).GetXValue());
	PARAM.SetAttr("o_compilado",Ctrl("o_compformula").GetXValue());

	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow","EditFormula",PARAM.ToString(),new objRefreshList("repFORMULA","o_formula","o_compformula"), "L");
}

function EditProceso()
{
	var PARAM=new NomadXML("PARAM");

	PARAM.SetAttr("oi_workflow",Ctrl("oi_workflow"  ).GetXValue());
	if ((Ctrl('main').GetMode()=="INI_EDIT") || (Ctrl('main').GetMode()=="FIN_EDIT") || (Ctrl('main').GetMode()=="TERMINAR_ADD") || (Ctrl('main').GetMode()=="TERMINAR_EDIT"))
	{
		PARAM.SetAttr("oi_process", Ctrl("PARENT").GetXValue());
	}
	if ((Ctrl('main').GetMode()=="CALL_ADD") || (Ctrl('main').GetMode()=="CALL_EDIT"))
	{
		PARAM.SetAttr("c_wf", Ctrl("d_param_1").GetXValue());
		PARAM.SetAttr("c_process", Ctrl("d_param_2").GetXValue());
	} 
	PARAM.SetAttr("o_formula"  ,Ctrl("o_process"    ).GetXValue());
	PARAM.SetAttr("o_compilado",Ctrl("o_compprocess").GetXValue());

	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow","EditProceso",PARAM.ToString(),new objRefreshList("repPROCESS","o_process","o_compprocess"), "L");
}

