function objRefreshList(ctrlName, formName, compName)
{                                                   
	this.ctrlName=ctrlName; 
	this.formName=formName; 
	this.compName=compName;

	this.processResult = function(xml)
	{
		var PARAM=new NomadXML(xml);
		if (PARAM.GetAttr("ACTION")=="ACCEPT")
		{
			Ctrl(this.formName).SetXValue(PARAM.GetAttr("o_formula"  ));
			Ctrl(this.compName).SetXValue(PARAM.GetAttr("o_compilado"));

			g_objEdit[this.ctrlName].SetText(PARAM.GetAttr("o_formula"  ));
		}
	}
}


var g_objEdit=new Array();

function InitEditorPROCESS(objEdit)        { InitEditor("repPROCESS"       , "o_process"       , objEdit); }
function InitEditorFORMULA(objEdit)        { InitEditor("repFORMULA"       , "o_formula"       , objEdit); }
function InitEditorPROCESS_BEFORE(objEdit) { InitEditor("repPROCESS_BEFORE", "o_process_before", objEdit); }
function InitEditorPROCESS_AFTER(objEdit)  { InitEditor("repPROCESS_AFTER" , "o_process_after" , objEdit); }

function InitEditor(mode, campo, objEdit)
{
	var param=new NomadXML("DATA");
	param.SetAttr("oi_workflow", Ctrl("oi_workflow").GetXValue());
	if ((Ctrl('main').GetMode()=="CALL_ADD") || (Ctrl('main').GetMode()=="CALL_EDIT"))
	{
		param.SetAttr("c_wf", Ctrl("d_param_1").GetXValue());
		param.SetAttr("c_process", Ctrl("d_param_2").GetXValue());
	} 
	if ((Ctrl('main').GetMode()=="METHOD_ADD") || (Ctrl('main').GetMode()=="METHOD_EDIT"))
	{
		param.SetAttr("im", Ctrl("d_param_1").GetXValue());
	} 
	if ((Ctrl('main').GetMode()=="INI_EDIT") || (Ctrl('main').GetMode()=="FIN_EDIT") || (Ctrl('main').GetMode()=="TERMINAR_ADD") || (Ctrl('main').GetMode()=="TERMINAR_EDIT"))
	{
		param.SetAttr("oi_process", Ctrl("PARENT").GetXValue());
	}

  //Consulta VARIABLES
  var nSQL = GetProxy().SQLService();
 	var xml=nSQL.GetXML(Ctrl("main").getResource("VARIABLES"), param.ToString());

 	//Agrega las VARIABLES
 	for (cur=xml.FirstChild(); cur!=null; cur=cur.Next())
 		objEdit.Syntax.AddVariable(cur.GetAttr("name"));

 	//Agrego el CODIGO                             
 	objEdit.SetText(Ctrl(campo).GetXValue());
 	objEdit.ReadOnly();

 	//Guardo el Objeto
 	g_objEdit[mode]=objEdit;
}

function mail_onvalidate(pObj)
{	
	var pFrom = Ctrl("d_param_3").GetXValue();
	var pMail = Ctrl("d_param_4").GetXValue();
	var format = /^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/;	

	if(pFrom=="CUS" & !pMail.match(format))
	{
		pObj.SetError("El correo electrónico ingresado no es válido");  
		return false;		
	}

	return true;
}

function remitente_onchange()
{
	if (Ctrl("d_param_3").GetXValue()!="CUS")
	{
		Ctrl("d_param_4").SetCValue("");
	  CtrlEnabled("d_param_4", false);
	}			
	else
	{
		CtrlEnabled("d_param_4", true);
	}
}
